xpath.script:
document.addEventListener('DOMContentLoaded', function() {
    const btnSendOtp = document.getElementById('btn_send_otp');
    const btnReset = document.getElementById('btn_reset_password');
    const otpDiv = document.getElementById('otp_div');
    const passDiv = document.getElementById('password_div');
    const loginInput = document.getElementById('login');

    if (btnSendOtp) {
        btnSendOtp.addEventListener('click', async function() {
            const email = loginInput.value;
            if (!email) {
                alert('Please enter your email.');
                return;
            }

            const response = await fetch('/ims/request_otp', {
                method: 'POST',
                headers: {'Content-Type': 'application/json'},
                body: JSON.stringify({params: {email: email}})
            });
            const data = await response.json();

            if (data.result && data.result.status === 'sent') {
                btnSendOtp.style.display = 'none';
                btnReset.style.display = 'block';
                otpDiv.style.display = 'block';
                passDiv.style.display = 'block';
                alert('OTP sent! Please check your email.');
            } else {
                alert('User not found or error sending OTP.');
            }
        });
    }
});
